var body = $json.body || $json;
var rawMessages = body.messages || [];
var messages = [];

for (var i = 0; i < rawMessages.length; i++) {
  var m = rawMessages[i];
  if (!m || typeof m !== "object") continue;
  var role = String(m.role || "").trim();
  if (!role) continue;

  if (Array.isArray(m.content)) {
    var hasContent = false;
    for (var c = 0; c < m.content.length; c++) {
      var part = m.content[c];
      if (part.type === "text" && part.text) hasContent = true;
      if (part.type === "image_url") hasContent = true;
      if (part.type === "image") hasContent = true;
    }
    if (hasContent) messages.push({ role: role, content: m.content });
  } else if (typeof m.content === "string" && m.content.trim()) {
    messages.push({ role: role, content: m.content });
  }
}

var userText = "";
for (var j = messages.length - 1; j >= 0; j--) {
  if (messages[j].role === "user") {
    if (typeof messages[j].content === "string") {
      userText = messages[j].content;
    } else if (Array.isArray(messages[j].content)) {
      var parts = [];
      for (var k = 0; k < messages[j].content.length; k++) {
        if (messages[j].content[k].type === "text") parts.push(messages[j].content[k].text || "");
      }
      userText = parts.join(" ");
      if (!userText) userText = "[Image uploaded]";
    }
    break;
  }
}

var lcText = userText.toLowerCase();
var isTitle = lcText.indexOf("title for the conversation") >= 0 || lcText.indexOf("concise title") >= 0 || lcText.indexOf("5-word") >= 0;

if (messages.length === 0) {
  messages.push({ role: "user", content: userText || "Hello" });
}

var hasImage = false;
for (var x = 0; x < messages.length; x++) {
  if (Array.isArray(messages[x].content)) {
    for (var y = 0; y < messages[x].content.length; y++) {
      if (messages[x].content[y].type === "image_url" || messages[x].content[y].type === "image") hasImage = true;
    }
  }
}

// -- Advisor email: look up from Cosmos DB using LibreChat user ID --
var advisorEmail = $env.ADVISOR_EMAIL || "rmabbun@dakona.com";
var librechatUserId = body.user || body.userId || "";
var emailSource = "fallback";

if (librechatUserId) {
  try {
    var cosmosUri = $env.COSMOS_LIBRECHAT_URI;
    if (cosmosUri) {
      var { MongoClient, ObjectId } = require("mongodb");
      var mongoClient = new MongoClient(cosmosUri, { serverSelectionTimeoutMS: 5000 });
      await mongoClient.connect();
      var usersCol = mongoClient.db("librechat").collection("users");

      var user = null;
      try {
        user = await usersCol.findOne({ _id: new ObjectId(librechatUserId) });
      } catch(e) {
        user = await usersCol.findOne({ _id: librechatUserId });
      }

      if (user && user.email) {
        advisorEmail = user.email;
        emailSource = "cosmos";
      }
      await mongoClient.close();
    }
  } catch(e) {
    console.log("Cosmos user lookup failed: " + e.message);
  }
}
console.log("advisorEmail source: " + emailSource + ", email: " + advisorEmail);

// -- Advisor timezone from Exchange mailbox --
var advisorTimezone = $env.ADVISOR_TIMEZONE || "America/New_York";
var currentDateTime = "";
var currentTime = "";

try {
  var tenantId = $env.GRAPH_TENANT_ID;
  var clientId = $env.GRAPH_CLIENT_ID;
  var clientSecret = $env.GRAPH_CLIENT_SECRET;

  if (tenantId && clientId && clientSecret) {
    var tokenUrl = "https://login.microsoftonline.com/" + tenantId + "/oauth2/v2.0/token";
    var tokenBody = "grant_type=client_credentials&client_id=" + clientId + "&client_secret=" + encodeURIComponent(clientSecret) + "&scope=https%3A%2F%2Fgraph.microsoft.com%2F.default";
    var tokenResp = await fetch(tokenUrl, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: tokenBody
    });
    var tokenData = await tokenResp.json();

    if (tokenData.access_token) {
      var mbResp = await fetch("https://graph.microsoft.com/v1.0/users/" + advisorEmail + "/mailboxSettings", {
        headers: { "Authorization": "Bearer " + tokenData.access_token }
      });
      if (mbResp.ok) {
        var mbData = await mbResp.json();
        if (mbData.timeZone) {
          var winToIana = {
            "Eastern Standard Time": "America/New_York",
            "Central Standard Time": "America/Chicago",
            "Mountain Standard Time": "America/Denver",
            "Pacific Standard Time": "America/Los_Angeles",
            "Alaska Standard Time": "America/Anchorage",
            "Hawaiian Standard Time": "Pacific/Honolulu",
            "Arizona": "America/Phoenix",
            "UTC": "UTC"
          };
          advisorTimezone = winToIana[mbData.timeZone] || mbData.timeZone;
        }
      }
    }
  }
} catch(e) {}

try {
  var now = new Date();
  currentDateTime = now.toLocaleString("en-US", {
    timeZone: advisorTimezone,
    weekday: "long", year: "numeric", month: "long", day: "numeric",
    hour: "numeric", minute: "2-digit", hour12: true
  });
  currentTime = now.toLocaleTimeString("en-US", {
    timeZone: advisorTimezone,
    hour: "numeric", minute: "2-digit", hour12: true
  });
} catch(e) {
  currentDateTime = new Date().toISOString();
  currentTime = new Date().toISOString();
}

var useProxy = isTitle || hasImage;
return [{ json: {
  userText: userText,
  isTitle: isTitle,
  hasImage: hasImage,
  useProxy: useProxy,
  originalMessages: messages,
  originalBody: body,
  advisorTimezone: advisorTimezone,
  currentDateTime: currentDateTime,
  currentTime: currentTime,
  advisorEmail: advisorEmail,
  librechatUserId: librechatUserId,
  emailSource: emailSource
} }];

var advisorTimezone = $env.ADVISOR_TIMEZONE || $input.all()[0]?.json?.advisorTimezone || 'America/New_York';
var https = require("https");

function auditLog(contactId, action, summary) {
  var d = JSON.stringify({ content: "[DAX] " + action + "\nDate: " + new Date().toLocaleString("en-US", { timeZone: advisorTimezone }) + "\nAdvisor: Demo Advisor\n" + summary + "\nGenerated by DAX v0.3.2", linked_to: [{ id: contactId, type: "Contact" }], tags: ["DAX", "Automated"] });
  var req = https.request({ hostname: "api.crmworkspace.com", path: "/v1/notes", method: "POST", headers: { "ACCESS_TOKEN": "2565bf3734934e0facbe77c7c2accd40", "Content-Type": "application/json", "Content-Length": Buffer.byteLength(d) } }, function() {});
  req.on("error", function() {});
  req.write(d); req.end();
}

function get(hostname, path, hdrs) {
  return new Promise(function(resolve) {
    https.get({ hostname: hostname, path: path, headers: hdrs || {} }, function(res) {
      var d = ""; res.on("data", function(c) { d += c; });
      res.on("end", function() { try { resolve(JSON.parse(d)); } catch(e) { resolve({}); } });
    }).on("error", function() { resolve({}); });
  });
}

var input = $input.all()[0].json || {};
var rawText = (input.userText || input.query || input.clientName || input.name || "").trim();

// Extract client name from natural language
var clientName = rawText
  .replace(/tell me about/i, "")
  .replace(/pull up/i, "")
  .replace(/look up/i, "")
  .replace(/show me/i, "")
  .replace(/what is/i, "")
  .replace(/what are/i, "")
  .replace(/what can you tell me about/i, "")
  .replace(/what do you know about/i, "")
  .replace(/i have a client named/i, "")
  .replace(/i have a client called/i, "")
  .replace(/my client/i, "")
  .replace(/'s risk.*$/i, "")
  .replace(/'s profile.*$/i, "")
  .replace(/'s goals.*$/i, "")
  .replace(/'s investment.*$/i, "")
  .replace(/'s info.*$/i, "")
  .replace(/'s background.*$/i, "")
  .replace(/'s meeting.*$/i, "")
  .replace(/risk profile.*$/i, "")
  .replace(/client info.*$/i, "")
  .replace(/[?.!,]/g, "")
  .trim();
if (!clientName) clientName = rawText.replace(/[?.!,]/g, "").trim();
if (!clientName) return "Please specify a client name.";

var wbData = await get("api.crmworkspace.com", "/v1/contacts?per_page=250", { "ACCESS_TOKEN": "2565bf3734934e0facbe77c7c2accd40" });
var allContacts = wbData.contacts || [];
var lcName = clientName.toLowerCase();
var nameParts = lcName.split(" ").filter(function(p) { return p.length > 0; });

// Strategy 1: exact full name match
var contact = null;
for (var i = 0; i < allContacts.length; i++) {
  if ((allContacts[i].name || "").toLowerCase() === lcName) { contact = allContacts[i]; break; }
}

// Strategy 2: all name parts present
if (!contact && nameParts.length >= 2) {
  for (var j = 0; j < allContacts.length; j++) {
    var cn = (allContacts[j].name || "").toLowerCase();
    var allMatch = true;
    for (var k = 0; k < nameParts.length; k++) {
      if (cn.indexOf(nameParts[k]) < 0) { allMatch = false; break; }
    }
    if (allMatch) { contact = allContacts[j]; break; }
  }
}

// Strategy 3: last name only
if (!contact && nameParts.length >= 1) {
  var lastName = nameParts[nameParts.length - 1];
  var lastMatches = allContacts.filter(function(c) {
    return (c.last_name || "").toLowerCase() === lastName || (c.name || "").toLowerCase().indexOf(lastName) >= 0;
  });
  if (lastMatches.length === 1) contact = lastMatches[0];
  else if (lastMatches.length > 1) {
    return "I found " + lastMatches.length + " clients matching \"" + clientName + "\": " + lastMatches.map(function(c) { return c.name; }).join(", ") + ". Which one did you mean?";
  }
}

// Strategy 4: first name only
if (!contact && nameParts.length >= 1) {
  var firstName = nameParts[0];
  var firstMatches = allContacts.filter(function(c) {
    return (c.first_name || "").toLowerCase() === firstName || (c.name || "").toLowerCase().indexOf(firstName) >= 0;
  });
  if (firstMatches.length === 1) contact = firstMatches[0];
  else if (firstMatches.length > 1) {
    return "I found " + firstMatches.length + " clients with that name: " + firstMatches.map(function(c) { return c.name; }).join(", ") + ". Which one did you mean?";
  }
}

// Not found -" be helpful
if (!contact) {
  var suggestions = allContacts.filter(function(c) {
    var cn = (c.name || "").toLowerCase();
    return nameParts.some(function(p) { return cn.indexOf(p) >= 0; });
  }).slice(0, 5);
  if (suggestions.length === 0) suggestions = allContacts.slice(0, 5);
  return "I searched Wealthbox but couldn't find \"" + clientName + "\". Did you mean one of these?\n" + suggestions.map(function(c) { return "- " + c.name; }).join("\n") + "\n\nSay \"show me all my clients\" to see everyone.";
}

// Found -" build response
var bg = contact.background_info || "";
var risk = contact.risk_tolerance || "Not specified";
var obj = contact.investment_objective || "Not specified";
var hor = contact.time_horizon || "Not specified";
var tagList = (contact.tags || []).map(function(t) { return typeof t === "object" ? t.name : String(t); });
var acct = "";
var cf = contact.custom_fields || [];
for (var m = 0; m < cf.length; m++) { if (cf[m].name === "account_number") { acct = cf[m].value; break; } }

var notesData = await get("api.crmworkspace.com", "/v1/notes?per_page=100", { "ACCESS_TOKEN": "2565bf3734934e0facbe77c7c2accd40" });
var notes = notesData.status_updates || [];
var noteContent = "";
for (var n = 0; n < notes.length; n++) {
  var nTags = notes[n].tags || [];
  for (var o = 0; o < nTags.length; o++) {
    if ((nTags[o].name || nTags[o]) === "Meeting") { noteContent = notes[n].content || ""; break; }
  }
  if (noteContent) break;
}
// Verify notes belong to this contact
var verifiedNotes = [];
for (var vn = 0; vn < notes.length; vn++) {
  var linkedTo = notes[vn].linked_to || [];
  var isLinked = false;
  for (var lt = 0; lt < linkedTo.length; lt++) {
    if (linkedTo[lt].id === contact.id) { isLinked = true; break; }
  }
  if (isLinked) verifiedNotes.push(notes[vn]);
}
notes = verifiedNotes;
noteContent = "";
for (var vk = 0; vk < notes.length; vk++) {
  var vnTags = notes[vk].tags || [];
  for (var vl = 0; vl < vnTags.length; vl++) {
    if ((vnTags[vl].name || vnTags[vl]) === "Meeting") { noteContent = notes[vk].content || ""; break; }
  }
  if (noteContent) break;
}
if (!noteContent && notes.length > 0) noteContent = notes[0].content || "";

// Audit log
auditLog(contact.id, "Client Profile Accessed", "Client: " + contact.name + " | Acct: " + (acct || "N/A"));

var lines = [
  contact.name,
  "Account: " + (acct || "N/A"),
  "Risk: " + risk + " | Objective: " + obj + " | Horizon: " + hor,
  "Interests: " + (tagList.join(", ") || "None"),
  bg ? "Background: " + bg.substring(0, 300) : "",
  noteContent ? "\nRecent Notes: " + noteContent.substring(0, 400) : ""
].filter(function(l) { return l; });

return lines.join("\n");

// Strip trailing filler closings that GPT-4o adds
var agentOutput = $json.output || $json.text || '';

// Split into sentences, check if last sentence is filler
var trimmed = agentOutput.trimEnd();
var sentences = trimmed.split(/(?<=[.!?])\s+/);

if (sentences.length > 1) {
  var last = sentences[sentences.length - 1].toLowerCase();
  var fillerStarts = [
    "if you have any", "if you need", "if you want",
    "feel free", "don't hesitate", "do not hesitate",
    "i'm here to help", "i am here to help",
    "let me know if", "just let me know",
    "happy to help", "hope this helps",
    "please let me know", "please feel free",
    "is there anything else", "if there's anything",
    "i'm always here", "i'm happy to"
  ];
  var isFiller = false;
  for (var f = 0; f < fillerStarts.length; f++) {
    if (last.indexOf(fillerStarts[f]) >= 0) {
      isFiller = true;
      break;
    }
  }
  if (isFiller) {
    sentences.pop();
    agentOutput = sentences.join(' ').trimEnd();
  }
}

const now = Math.floor(Date.now() / 1000);
const id = 'chatcmpl-dax-' + now;

const c1 = JSON.stringify({ id, object: 'chat.completion.chunk', created: now, model: 'gpt-4o', choices: [{ index: 0, delta: { role: 'assistant', content: '' }, finish_reason: null }] });
const c2 = JSON.stringify({ id, object: 'chat.completion.chunk', created: now, model: 'gpt-4o', choices: [{ index: 0, delta: { content: agentOutput }, finish_reason: null }] });
const c3 = JSON.stringify({ id, object: 'chat.completion.chunk', created: now, model: 'gpt-4o', choices: [{ index: 0, delta: {}, finish_reason: 'stop' }] });
const sseBody = 'data: ' + c1 + '\n\ndata: ' + c2 + '\n\ndata: ' + c3 + '\n\ndata: [DONE]\n\n';

// Pass user message through for compliance flag check
const _webhookInput = $('Webhook').first().json;
const _body = _webhookInput.body || _webhookInput;
const _msgs = _body.messages || [];
const _userMessage = _msgs.length > 0 ? (_msgs[_msgs.length - 1].content || '') : (_body.message || _body.text || '');
return [{ json: { sseBody, _userMessage, _agentOutput: agentOutput } }];

var https = require("https");
var input = $input.all()[0].json || {};

// Extract symbols from agent input or userText
var rawSymbols = input.query || input.symbols || input.symbol || "";
if (!rawSymbols && input.userText) {
  var text = input.userText;
  var lc = text.toLowerCase();
  // Map common names
  var names = { "apple": "AAPL", "microsoft": "MSFT", "google": "GOOGL", "amazon": "AMZN", "nvidia": "NVDA", "tesla": "TSLA", "meta": "META", "netflix": "NFLX", "s&p": "SPY", "sp500": "SPY", "nasdaq": "QQQ", "dow": "DIA", "gold": "GC=F", "oil": "CL=F", "crude": "CL=F", "bitcoin": "BTC-USD", "fed funds": "^IRX", "fed rate": "^IRX", "federal funds": "^IRX", "10 year": "^TNX", "treasury": "^TNX", "vix": "^VIX", "dollar": "DX-Y.NYB", "the market": "SPY", "markets": "SPY" };
  for (var nm in names) { if (lc.indexOf(nm) >= 0) { rawSymbols = names[nm]; break; } }
  // Extract explicit tickers (2-5 uppercase letters surrounded by non-letters)
  if (!rawSymbols) {
    var words = text.split(/[^A-Za-z]+/);
    var stops = ["What","How","Is","The","At","It","In","My","Do","For","To","And","Or","Are","Has","Was","Can","Get","Me","Of","On","An","By","So","No","If","Up","Am","As","Be","We"];
    for (var w = 0; w < words.length; w++) {
      var word = words[w];
      if (word.length >= 2 && word.length <= 5 && word === word.toUpperCase() && stops.indexOf(word) < 0) {
        rawSymbols = word; break;
      }
    }
  }
}
if (!rawSymbols) rawSymbols = "SPY";
var symbols = rawSymbols.split(",").map(function(s) { return s.trim().toUpperCase(); }).filter(Boolean).slice(0, 10);
if (symbols.length === 0) symbols = ["SPY"];

function fetchQuote(symbol) {
  return new Promise(function(resolve) {
    var path = "/v8/finance/chart/" + encodeURIComponent(symbol) + "?interval=1d&range=1d";
    https.get({
      hostname: "query1.finance.yahoo.com",
      path: path,
      headers: {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
        "Accept": "application/json",
        "Referer": "https://finance.yahoo.com/"
      }
    }, function(res) {
      var data = "";
      res.on("data", function(c) { data += c; });
      res.on("end", function() {
        try {
          var j = JSON.parse(data);
          var meta = j.chart && j.chart.result && j.chart.result[0] && j.chart.result[0].meta;
          if (!meta) { resolve({ symbol: symbol, error: "No data" }); return; }
          var price = meta.regularMarketPrice;
          var prev = meta.chartPreviousClose || meta.previousClose;
          var change = prev ? (price - prev) : 0;
          var pct = prev ? ((change / prev) * 100) : 0;
          var name = meta.shortName || meta.longName || symbol;
          var isRate = ["^IRX", "^TNX", "^FVX", "^TYX"].indexOf(symbol) >= 0;
          resolve({
            symbol: symbol,
            name: name,
            price: isRate ? price.toFixed(3) + "%" : "$" + price.toFixed(2),
            change: (change >= 0 ? "+" : "") + (isRate ? change.toFixed(3) : change.toFixed(2)),
            changePct: (pct >= 0 ? "+" : "") + pct.toFixed(2) + "%",
            high52: meta.fiftyTwoWeekHigh ? "$" + meta.fiftyTwoWeekHigh.toFixed(2) : "N/A",
            low52: meta.fiftyTwoWeekLow ? "$" + meta.fiftyTwoWeekLow.toFixed(2) : "N/A"
          });
        } catch(e) {
          resolve({ symbol: symbol, error: "Parse error" });
        }
      });
      res.on("error", function() { resolve({ symbol: symbol, error: "Fetch error" }); });
    }).on("error", function() { resolve({ symbol: symbol, error: "Connection error" }); });
  });
}

var results = await Promise.all(symbols.map(function(s) { return fetchQuote(s); }));

var formatted = results.map(function(r) {
  if (r.error) return r.symbol + ": " + r.error;
  return r.symbol + " (" + r.name + "): " + r.price + " (" + r.changePct + " today) | 52-week: " + r.low52 + " - " + r.high52;
}).join("\n");

return formatted;

var advisorTimezone = $env.ADVISOR_TIMEZONE || $input.all()[0]?.json?.advisorTimezone || 'America/New_York';
var https = require("https");

function auditLog(contactId, action, summary, details) {
  var d = JSON.stringify({ content: "[DAX] " + action + "\nDate: " + new Date().toLocaleString("en-US", { timeZone: advisorTimezone }) + "\nAdvisor: Demo Advisor\n" + (summary || "") + "\nGenerated by DAX v0.3.0", linked_to: [{ id: contactId, type: "Contact" }], tags: ["DAX", "Automated"] });
  var req = https.request({ hostname: "api.crmworkspace.com", path: "/v1/notes", method: "POST", headers: { "ACCESS_TOKEN": "2565bf3734934e0facbe77c7c2accd40", "Content-Type": "application/json", "Content-Length": Buffer.byteLength(d) } }, function() {});
  req.on("error", function() {});
  req.write(d); req.end();
}

var input = $input.all()[0].json || {};
var searchTerm = (input.query || input.searchTerm || input.filter || "").toLowerCase().trim();

var contacts = await new Promise(function(resolve) {
  https.get({ hostname: "api.crmworkspace.com", path: "/v1/contacts?per_page=250", headers: { "ACCESS_TOKEN": "2565bf3734934e0facbe77c7c2accd40" } }, function(res) {
    var data = ""; res.on("data", function(c) { data += c; });
    res.on("end", function() { try { resolve(JSON.parse(data).contacts || []); } catch(e) { resolve([]); } });
  }).on("error", function() { resolve([]); });
});

var filtered = contacts;
if (searchTerm) {
  filtered = contacts.filter(function(c) {
    var tags = (c.tags || []).map(function(t) { return (typeof t === "object" ? t.name : String(t)).toLowerCase(); });
    var all = (c.name || "").toLowerCase() + " " + (c.background_info || "").toLowerCase() + " " + (c.risk_tolerance || "").toLowerCase() + " " + (c.investment_objective || "").toLowerCase() + " " + tags.join(" ");
    return all.indexOf(searchTerm) >= 0;
  });
}

var getAcct = function(cf) { var f = (cf || []).find(function(x) { return x.name === "account_number"; }); return f ? f.value : "N/A"; };

var list = filtered.map(function(c) {
  var tags = (c.tags || []).map(function(t) { return typeof t === "object" ? t.name : String(t); });
  return "- " + c.name + " | Acct: " + getAcct(c.custom_fields) + " | Risk: " + (c.risk_tolerance || "N/A") + " | Obj: " + (c.investment_objective || "N/A") + (tags.length ? " | Tags: " + tags.join(", ") : "");
}).join("\n");

// Audit log for filtered searches only
if (searchTerm && filtered.length > 0) {
  auditLog(filtered[0].id, "Client List Searched", "Filter: " + searchTerm + " | Found: " + filtered.length, {});
}

var result = filtered.length > 0
  ? "Found " + filtered.length + " of " + contacts.length + " clients" + (searchTerm ? " matching \"" + searchTerm + "\"" : "") + ":\n\n" + list
  : "No clients found matching \"" + searchTerm + "\". Total: " + contacts.length;

return result;

var advisorEmail = $input.all()[0]?.json?.advisorEmail || $env.ADVISOR_EMAIL || "rmabbun@dakona.com";
var advisorTimezone = $env.ADVISOR_TIMEZONE || $input.all()[0]?.json?.advisorTimezone || 'America/New_York';
var https = require("https");
var input = $input.all()[0].json || {};

// Extract client name from user text
var userText = input.userText || input.query || input.clientName || "";
var clientName = userText
  .replace(/prep me for my meeting with/i, "")
  .replace(/my meeting with/i, "")
  .replace(/meeting with/i, "")
  .replace(/prepare for/i, "")
  .replace(/get me ready for/i, "")
  .replace(/meeting prep for/i, "")
  .replace(/prep me for/i, "")
  .replace(/meeting prep/i, "")
  .replace(/prep for/i, "")
  .replace(/prep/i, "")
  .trim();
if (!clientName) clientName = userText.trim();
if (!clientName) return "Please specify a client name.";

// HTTP helper - no URL constructor
function get(hostname, path, hdrs) {
  return new Promise(function(resolve) {
    https.get({ hostname: hostname, path: path.split(" ").join("%20"), headers: hdrs || {} }, function(res) {
