      return (i+1) + ". " + h.title + "\n   " + (h.summary || "") + "\n   " + h.source + " | " + h.published;
    }).join("\n\n")
  : "No market news available.";

return "MARKET SUMMARY - " + today + "\n\nKEY INDICES\n" + (snapshot || "Price data unavailable") + "\n\nTOP MARKET STORIES\n" + headlineText + "\n\nSource: FMP/Finnhub live data";

var advisorEmail = $input.all()[0]?.json?.advisorEmail || $env.ADVISOR_EMAIL || "rmabbun@dakona.com";
var advisorTimezone = $env.ADVISOR_TIMEZONE || $input.all()[0]?.json?.advisorTimezone || "America/New_York";
var https = require("https");
var input = $input.all()[0]?.json || {};
var userText = input.userText || input.query || "";

// The agent generates the full document content and passes it via tool call
// In n8n toolCode, the agent's tool args come via $input.all()[0].json
// but this workflow passes Extract Message output instead.
// So we read the userText (the user's original request) and the agent
// should have already generated the content in its reasoning.
// We'll ask the agent to pass the content directly.

// Try to extract title and content from the user's message
var title = "DAX Document - " + new Date().toISOString().split("T")[0];
var content = userText;

// If the message contains explicit title/content markers
var titleMatch = userText.match(/title[:\s]+["']?([^"'\n]+)/i);
if (titleMatch) title = titleMatch[1].trim();

var contentMatch = userText.match(/content[:\s]+["']?(.+)/is);
if (contentMatch) content = contentMatch[1].trim();

if (!content || content.length < 10) {
  return "I need more text to create the document. Please provide the full content you want saved.";
}

// Get Graph token
function httpsReq(method, hostname, path, headers, body) {
  return new Promise(function(resolve) {
    var opts = { hostname: hostname, path: path, method: method, headers: headers || {} };
    var req = https.request(opts, function(res) {
      var data = "";
      res.on("data", function(chunk) { data += chunk; });
      res.on("end", function() { resolve({ status: res.statusCode, body: data }); });
    });
    req.on("error", function(e) { resolve({ status: 0, body: e.message }); });
    if (body) req.write(body);
    req.end();
  });
}

var tokenBody = "client_id=218064ac-bee2-4246-9709-ae7518ae71cb&client_secret=6LR8Q~ZCn5FTBlg894LtCGlXZ9GV3NAhS4BY9bla&scope=https%3A%2F%2Fgraph.microsoft.com%2F.default&grant_type=client_credentials";
var tokenRes = await httpsReq("POST", "login.microsoftonline.com", "/d2a3c346-00f3-47dd-a53e-caa3fca74714/oauth2/v2.0/token", { "Content-Type": "application/x-www-form-urlencoded", "Content-Length": tokenBody.length }, tokenBody);
var tokenData = {};
try { tokenData = JSON.parse(tokenRes.body); } catch(e) {}
if (!tokenData.access_token) return "Error: Could not authenticate to Microsoft Graph";
var gToken = tokenData.access_token;

// Build file
var safeName = title.replace(/[^a-zA-Z0-9 -]/g, "").replace(/\s+/g, "-").substring(0, 50);
var fileName = safeName + ".txt";
var ts = new Date().toLocaleString("en-US", { timeZone: advisorTimezone });
var fileContent = title + "\n" + Array(title.length + 1).join("=") + "\n\n" + content + "\n\n---\nGenerated by DAX | " + ts + " | Advisor: " + advisorEmail;

// Upload to SharePoint via site default drive
var siteId = "dakonallc.sharepoint.com,68764500-f333-44cc-8017-30489a6a9053,71b1b423-6196-4e05-b004-7298445afb6f";
var encodedFileName = fileName.replace(/ /g, "%20");
var uploadPath = "/v1.0/sites/" + siteId + "/drive/root:/DAX%20Documents/" + encodedFileName + ":/content";

var uploadRes = await httpsReq("PUT", "graph.microsoft.com", uploadPath, { "Authorization": "Bearer " + gToken, "Content-Type": "text/plain", "Content-Length": Buffer.byteLength(fileContent) }, fileContent);

if (uploadRes.status === 200 || uploadRes.status === 201) {
  var uploadData = {};
  try { uploadData = JSON.parse(uploadRes.body); } catch(e) {}
  return "Document saved to SharePoint successfully:\n- Title: " + title + "\n- File: DAX Documents/" + fileName + "\n- URL: " + (uploadData.webUrl || "Check SharePoint") + "\n- Size: " + fileContent.length + " characters";
}

return "Error uploading to SharePoint: HTTP " + uploadRes.status + " - " + uploadRes.body.substring(0, 200);
